// // This module implements a 2-to-1 multiplexer where the output is selected based on the 'select' signal. When 'select' is 0, 'out' outputs 'input2', and when 'select' is 1, 'out' outputs 'input1'.
module top_module(input1, input2, select, out);input input1;    
	input input2;    
	input select;    

	output out;      

	assign out = ((~select) & input1) | (select & input2);endmodule
